### Create `rust/crates/app/src/ui/context_bar.rs`

```rust
use ratatui::{
    layout::Rect,
    style::{Color, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};
use crate::state::{PinKind, TabState};

fn pin_icon(kind: &PinKind) -> &'static str {
    match kind {
        PinKind::Skill => "⚡",
        PinKind::File => "📄",
        PinKind::Dir => "📁",
    }
}

fn truncate_path(path: &str) -> String {
    let parts: Vec<&str> = path.split('/').filter(|s| !s.is_empty()).collect();
    if parts.len() <= 2 {
        return path.to_string();
    }
    format!("…/{}/{}", parts[parts.len() - 2], parts[parts.len() - 1])
}

pub fn render_context_bar(f: &mut Frame, tab: Option<&TabState>, area: Rect) {
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::DarkGray));

    let inner = block.inner(area);
    f.render_widget(block, area);

    let pins = tab.map(|t| t.pins.as_slice()).unwrap_or(&[]);

    if pins.is_empty() {
        let hint = Paragraph::new("No context — @file /skill to pin")
            .style(Style::default().fg(Color::DarkGray));
        f.render_widget(hint, inner);
        return;
    }

    let mut spans: Vec<Span> = Vec::new();
    let selected_idx = tab.map(|t| t.pin_selected).unwrap_or(0);

    for (i, pin) in pins.iter().enumerate() {
        let selected = i == selected_idx;
        let base_style = if selected || pin.sticky {
            Style::default().fg(Color::Cyan)
        } else {
            Style::default().fg(Color::Yellow)
        };
        let label = format!("{}{}", pin_icon(&pin.kind), truncate_path(&pin.display));
        let suffix = if !pin.sticky { " (1x)" } else { "" };
        spans.push(Span::styled(
            format!("[{}{}] ", label, suffix),
            base_style,
        ));
    }

    let para = Paragraph::new(Line::from(spans));
    f.render_widget(para, inner);
}
