use ratatui::{
    Frame,
    layout::{Constraint, Layout, Rect},
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Tabs},
};
use crate::state::{AppState, LayoutState};

pub struct ColumnAreas {
    pub tab_bar: Rect,
    pub left: Rect,
    pub center: Rect,
    pub right: Rect,
    pub left_border_col: u16,
    pub right_border_col: u16,
}

pub fn compute_columns(layout: &LayoutState, area: Rect) -> ColumnAreas {
    let vertical = Layout::vertical([Constraint::Length(3), Constraint::Min(0)]).split(area);
    let tab_bar = vertical[0];
    let body = vertical[1];

    let left_w = if layout.left_visible { layout.left_width() } else { 0 };
    let right_w = if layout.right_visible { layout.right_width() } else { 0 };
    let center_w = body.width.saturating_sub(left_w + right_w);

    let cols = Layout::horizontal([
        Constraint::Length(left_w),
        Constraint::Length(center_w),
        Constraint::Length(right_w),
    ])
    .split(body);

    let left_border_col = if layout.left_visible {
        cols[0].right().saturating_sub(1)
    } else {
        0
    };
    let right_border_col = if layout.right_visible { cols[2].x } else { u16::MAX };

    ColumnAreas {
        tab_bar,
        left: cols[0],
        center: cols[1],
        right: cols[2],
        left_border_col,
        right_border_col,
    }
}

pub fn render_tab_bar(f: &mut Frame, state: &AppState, area: Rect) {
    let titles: Vec<Line> = state
        .tabs
        .iter()
        .enumerate()
        .map(|(i, tab)| {
            let style = if i == state.active_tab {
                Style::default()
                    .fg(Color::Cyan)
                    .add_modifier(Modifier::BOLD)
            } else {
                Style::default().fg(Color::Gray)
            };
            Line::from(Span::styled(format!(" {} ", tab.name), style))
        })
        .collect();

    let tabs = Tabs::new(titles)
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_type(BorderType::Rounded),
        )
        .select(state.active_tab)
        .highlight_style(
            Style::default()
                .fg(Color::Cyan)
                .add_modifier(Modifier::BOLD),
        )
        .divider("|");
    f.render_widget(tabs, area);
}

