use std::sync::Arc;
use tokio::sync::mpsc;
use clui_agent::{AgentClient, AgentConfig, AgentEvent};
use crate::event::AppEvent;

#[derive(Debug)]
pub enum AgentCommand {
    SendPrompt { text: String },
    Interrupt,
}

pub fn spawn_agent(
    tab_id: String,
    config: AgentConfig,
    event_tx: mpsc::Sender<AppEvent>,
) -> Arc<mpsc::Sender<AgentCommand>> {
    let (cmd_tx, mut cmd_rx) = mpsc::channel::<AgentCommand>(32);

    tokio::spawn(async move {
        let mut client = AgentClient::new(config);
        loop {
            match cmd_rx.recv().await {
                None => break,
                Some(AgentCommand::Interrupt) => {}
                Some(AgentCommand::SendPrompt { text }) => {
                    let (chunk_tx, mut chunk_rx) = mpsc::channel::<AgentEvent>(128);
                    let tid = tab_id.clone();
                    let etx = event_tx.clone();

                    tokio::spawn(async move {
                        while let Some(evt) = chunk_rx.recv().await {
                            let app_event = match evt {
                                AgentEvent::StreamChunk(content) => AppEvent::AgentChunk {
                                    tab_id: tid.clone(),
                                    content,
                                },
                                AgentEvent::MessageComplete {
                                    content,
                                    output_tokens,
                                } => AppEvent::AgentComplete {
                                    tab_id: tid.clone(),
                                    content,
                                    tokens: output_tokens,
                                    cost: 0.0,
                                },
                                AgentEvent::Error(message) => AppEvent::AgentError {
                                    tab_id: tid.clone(),
                                    message,
                                },
                            };
                            let _ = etx.send(app_event).await;
                        }
                    });

                    if let Err(e) = client.send(text, None, chunk_tx).await {
                        let _ = event_tx
                            .send(AppEvent::AgentError {
                                tab_id: tab_id.clone(),
                                message: e.to_string(),
                            })
                            .await;
                    }
                }
            }
        }
    });

    Arc::new(cmd_tx)
}

mod agent_task;
mod event;
mod router;
mod state;
mod ui;

use std::io;
use std::time::Duration;

use anyhow::Result;
use crossterm::{
    event::{
        self, DisableMouseCapture, EnableMouseCapture, Event,
        poll as crossterm_poll, read as crossterm_read,
    },
    execute,
    terminal::{disable_raw_mode, enable_raw_mode, EnterAlternateScreen, LeaveAlternateScreen},
};
use ratatui::{backend::CrosstermBackend, Terminal};
use tokio::sync::mpsc;

use event::AppEvent;
use state::{AppState, TabKind};

#[tokio::main]
async fn main() -> Result<()> {
    let cwd = std::env::current_dir()?;

    enable_raw_mode()?;
    let mut stdout = io::stdout();
    execute!(stdout, EnterAlternateScreen, EnableMouseCapture)?;
    let backend = CrosstermBackend::new(io::stdout());
    let mut terminal = Terminal::new(backend)?;
    terminal.clear()?;

    let size = terminal.size()?;
    let mut app = AppState::new(cwd);
    app.layout.terminal_cols = size.width;
    app.layout.terminal_rows = size.height;

    let result = run_loop(&mut terminal, &mut app).await;

    disable_raw_mode()?;
    execute!(io::stdout(), LeaveAlternateScreen, DisableMouseCapture)?;
    terminal.show_cursor()?;

    result
}

async fn run_loop(
    terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
    state: &mut AppState,
) -> Result<()> {
    let settings = clui_config::Settings::from_env();
    let (event_tx, mut event_rx) = mpsc::channel::<AppEvent>(256);

    // Spawn agent for initial tab if API key available
    if let Some(api_key) = &settings.anthropic_api_key {
        let config = clui_agent::AgentConfig {
            api_key: api_key.clone(),
            model: settings.default_model.clone(),
            max_tokens: 8192,
            cwd: state.cwd.to_string_lossy().to_string(),
        };
        let tx = agent_task::spawn_agent(state.tabs[0].id.clone(), config, event_tx.clone());
        if let TabKind::Chat { agent_tx } = &mut state.tabs[0].kind {
            *agent_tx = Some(tx);
        }
    }

    // Initial git refresh
    let _ = event_tx.send(AppEvent::GitRefresh).await;

    // Spawn git watcher
    let etx_git = event_tx.clone();
    tokio::spawn(async move {
        loop {
            tokio::time::sleep(Duration::from_secs(5)).await;
            let _ = etx_git.send(AppEvent::GitRefresh).await;
        }
    });

    loop {
        terminal.draw(|f| ui::render(f, state))?;

        // Drain async events
        while let Ok(evt) = event_rx.try_recv() {
            router::handle(state, evt);
        }

        if crossterm_poll(Duration::from_millis(16))? {
            match crossterm_read()? {
                Event::Key(k) => router::handle(
                    state,
                    AppEvent::Key {
                        code: k.code,
                        modifiers: k.modifiers,
                    },
                ),
                Event::Mouse(m) => router::handle(
                    state,
                    AppEvent::Mouse {
                        kind: m.kind,
                        col: m.column,
                        row: m.row,
                        modifiers: m.modifiers,
                    },
                ),
                Event::Resize(c, r) => {
                    router::handle(state, AppEvent::Resize { cols: c, rows: r })
                }
                _ => {}
            }
        } else {
            router::handle(state, AppEvent::Tick);
        }

        // Dispatch pending prompts to agent
        if let Some(tab) = state.active_tab_mut() {
            if let Some(prompt) = tab.pending_prompt.take() {
                if let TabKind::Chat {
                    agent_tx: Some(tx),
                } = &tab.kind
                {
                    let _ = tx
                        .send(agent_task::AgentCommand::SendPrompt { text: prompt })
                        .await;
                }
            }
        }

        if state.should_quit {
            break;
        }
    }
    Ok(())
}

