AppEvent::Key { code: KeyCode::Left, modifiers } if modifiers.contains(KeyModifiers::ALT) => {
    if let Some(tab) = state.active_tab_mut() {
        if tab.pin_selected > 0 { tab.pin_selected -= 1; }
    }
}
AppEvent::Key { code: KeyCode::Right, modifiers } if modifiers.contains(KeyModifiers::ALT) => {
    if let Some(tab) = state.active_tab_mut() {
        let len = tab.pins.len();
        if len > 0 && tab.pin_selected < len - 1 { tab.pin_selected += 1; }
    }
}
AppEvent::Key { code: KeyCode::Char('x'), modifiers } if modifiers.contains(KeyModifiers::ALT) => {
    if let Some(tab) = state.active_tab_mut() {
        let idx = tab.pin_selected;
        if idx < tab.pins.len() {
            tab.pins.remove(idx);
            if tab.pin_selected >= tab.pins.len() && tab.pin_selected > 0 {
                tab.pin_selected -= 1;
            }
        }
    }
}
